// State transitions:
// - INIT -> OFF: Controller initialized, PSU is off
// - OFF -> ON_NOT_READY: PSU enabled, voltage ramping
// - ON_NOT_READY -> ON_READY: Output voltage stable at target
// - ON_READY -> OFF: PSU disabled
// - ANY (except FIRMWARE_UPDATING, DISCONNECTED) -> ERROR_RECOVERABLE: PSU fault detected (saves pre-error config)
// - ERROR_RECOVERABLE -> RECOVERING: Attempting auto-recovery
// - RECOVERING -> ERROR_RECOVERABLE: Always returns (whether success or failure)
// - ERROR_RECOVERABLE -> ON_NOT_READY/OFF: Faults cleared (restores pre-error config)
// - ERROR_RECOVERABLE -> ERROR_FATAL: Recovery limit exceeded
// - ERROR_FATAL -> ERROR_RECOVERABLE: ResetRecoveryLimits command
// - ANY -> DISCONNECTED: PSU physically unplugged
// - ANY (except DISCONNECTED) -> FIRMWARE_UPDATING: PSU in bootloader/update mode
// - DISCONNECTED -> OFF: PSU reconnected
// - FIRMWARE_UPDATING -> OFF: Update complete, PSU reconnected
type PsuControllerState int32

const (
	PsuControllerState_PSU_CONTROLLER_STATE_INIT              PsuControllerState = 0
	PsuControllerState_PSU_CONTROLLER_STATE_OFF               PsuControllerState = 1
	PsuControllerState_PSU_CONTROLLER_STATE_ON_READY          PsuControllerState = 2 // Output voltage ready and on
	PsuControllerState_PSU_CONTROLLER_STATE_ON_NOT_READY      PsuControllerState = 3 // Output voltage NOT ready/stable yet
	PsuControllerState_PSU_CONTROLLER_STATE_ERROR_RECOVERABLE PsuControllerState = 4 // Connected but has faults, recovery possible
	PsuControllerState_PSU_CONTROLLER_STATE_RECOVERING        PsuControllerState = 5
	PsuControllerState_PSU_CONTROLLER_STATE_FIRMWARE_UPDATING PsuControllerState = 6 // In bootloader/update mode
	PsuControllerState_PSU_CONTROLLER_STATE_DISCONNECTED      PsuControllerState = 7 // Physically unplugged
	PsuControllerState_PSU_CONTROLLER_STATE_ERROR_FATAL       PsuControllerState = 8 // Recovery limit exceeded, requires reset or disconnect
)

